PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "users_customuser_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "customuser_id" bigint NOT NULL REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "users_customuser_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "customuser_id" bigint NOT NULL REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "api_brand" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(255) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "authtoken_token" ("key" varchar(40) NOT NULL PRIMARY KEY, "created" datetime NOT NULL, "user_id" bigint NOT NULL UNIQUE REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "users_customuser" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "first_name" varchar(150) NOT NULL, "last_name" varchar(150) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "email" varchar(254) NOT NULL UNIQUE, "role" varchar(30) NOT NULL);
CREATE TABLE IF NOT EXISTS "api_clientowner" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "created_at" datetime NOT NULL, "client_id" bigint NOT NULL REFERENCES "api_client" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED, CONSTRAINT "uniq_client_owner_user_client" UNIQUE ("user_id", "client_id"));
CREATE TABLE IF NOT EXISTS "api_client" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(255) NOT NULL, "client_interface" varchar(255) NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "client_interface_contact_number" varchar(20) NOT NULL, "logo" varchar(100) NULL, "accent_color" varchar(7) NOT NULL);
CREATE TABLE IF NOT EXISTS "api_servicecategory" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(255) NOT NULL UNIQUE, "description" text NOT NULL);
CREATE TABLE IF NOT EXISTS "api_negativeremarkontask" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "negative_remark_id" bigint NOT NULL REFERENCES "api_negativeremark" ("id") DEFERRABLE INITIALLY DEFERRED, "task_id" bigint NOT NULL REFERENCES "api_task" ("id") DEFERRABLE INITIALLY DEFERRED, CONSTRAINT "uniq_negative_remark_on_task" UNIQUE ("task_id", "negative_remark_id"));
CREATE TABLE IF NOT EXISTS "api_negativeremark" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "remark_name" varchar(255) NOT NULL, "description" text NOT NULL, "point" decimal NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "api_taskattachment" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "file" varchar(100) NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "task_id" bigint NOT NULL REFERENCES "api_task" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "api_clientattachment" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "file" varchar(100) NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "client_id" bigint NOT NULL REFERENCES "api_client" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "api_scopeofwork_type_of_work" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "scopeofwork_id" bigint NOT NULL REFERENCES "api_scopeofwork" ("id") DEFERRABLE INITIALLY DEFERRED, "typeofwork_id" bigint NOT NULL REFERENCES "api_typeofwork" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "users_employee" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "designation" varchar(255) NOT NULL, "salary" decimal NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "user_id" bigint NOT NULL UNIQUE REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "api_scopeofwork" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "description" text NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "client_id" bigint NOT NULL REFERENCES "api_client" ("id") DEFERRABLE INITIALLY DEFERRED, "deliverable_name" varchar(150) NOT NULL, "total_unit" integer unsigned NOT NULL CHECK ("total_unit" >= 0), "service_category_id" bigint NOT NULL REFERENCES "api_servicecategory" ("id") DEFERRABLE INITIALLY DEFERRED, CONSTRAINT "uniq_scope_of_work_client_service_category" UNIQUE ("client_id", "service_category_id"));
CREATE TABLE IF NOT EXISTS "api_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(255) NOT NULL UNIQUE, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "api_groupmember" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "created_at" datetime NOT NULL, "group_id" bigint NOT NULL REFERENCES "api_group" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED, CONSTRAINT "uniq_group_member_group_user" UNIQUE ("group_id", "user_id"));
CREATE TABLE IF NOT EXISTS "api_typeofwork" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "work_type_name" varchar(255) NOT NULL UNIQUE, "point" real NOT NULL, "major_changes_point" real NOT NULL, "minor_changes_point" real NOT NULL, "redo_point" real NOT NULL);
CREATE TABLE IF NOT EXISTS "api_clientmonthlyamount" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "date" date NOT NULL, "amt" decimal NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "client_id" bigint NOT NULL REFERENCES "api_client" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "api_taskstage" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(255) NOT NULL UNIQUE, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "api_taskonstage" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "task_id" bigint NOT NULL REFERENCES "api_task" ("id") DEFERRABLE INITIALLY DEFERRED, "task_stage_id" bigint NOT NULL REFERENCES "api_taskstage" ("id") DEFERRABLE INITIALLY DEFERRED, CONSTRAINT "uniq_task_on_stage_task" UNIQUE ("task_id"));
CREATE TABLE IF NOT EXISTS "api_task" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "task_name" varchar(255) NOT NULL, "instructions" text NOT NULL, "revision_count" integer unsigned NOT NULL CHECK ("revision_count" >= 0), "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "designer_id" bigint NULL REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED, "revision_no" integer unsigned NULL CHECK ("revision_no" >= 0), "client_id" bigint NULL REFERENCES "api_client" ("id") DEFERRABLE INITIALLY DEFERRED, "target_date" date NULL, "priority" varchar(10) NOT NULL, "redo_count" integer unsigned NOT NULL CHECK ("redo_count" >= 0), "redo_no" integer unsigned NULL CHECK ("redo_no" >= 0), "type_of_work_id" bigint NULL REFERENCES "api_typeofwork" ("id") DEFERRABLE INITIALLY DEFERRED, "InstructionsByArtDirector" text NULL, "created_by_id" bigint NULL REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED, "excellence" decimal NULL, "scope_of_work_id" bigint NULL REFERENCES "api_scopeofwork" ("id") DEFERRABLE INITIALLY DEFERRED, "revision_type" varchar(10) NOT NULL, "have_major_changes" bool NOT NULL, "have_minor_changes" bool NOT NULL, "slides" integer unsigned NOT NULL CHECK ("slides" >= 0), "excellence_reason" text NULL, "stage" varchar(64) NOT NULL, "ctr" decimal NULL, "impressions" integer unsigned NULL CHECK ("impressions" >= 0), "promotion_type" varchar(16) NOT NULL, "engagement_rate" decimal NULL, "platform" varchar(32) NOT NULL, "revision_of_id" bigint NULL REFERENCES "api_task" ("id") DEFERRABLE INITIALLY DEFERRED, "redo_of_id" bigint NULL REFERENCES "api_task" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "api_additionalpoints" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "points" decimal NOT NULL, "date" date NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "user_id" bigint NOT NULL REFERENCES "users_customuser" ("id") DEFERRABLE INITIALLY DEFERRED);
